import { Component, OnInit } from '@angular/core';
import { AuthService } from 'src/app/services/auth.service';
import { Router } from '@angular/router';

@Component({
  selector: 'app-perfil',
  templateUrl: './perfil.component.html',
  styleUrls: ['./perfil.component.css']
})
export class PerfilComponent implements OnInit {
  userName: string = '';
  userEmail: string = '';
  emailVerified: boolean = false; // 🔹 Corrigido para iniciar como false
  verificationMessage: string = '';

  constructor(private authService: AuthService, private router: Router) {}

  ngOnInit(): void {
    this.userName = this.authService.getUserName();
    this.userEmail = this.authService.getUserEmail();

    this.authService.getUserVerificationStatus().subscribe({
      next: (response) => {
        console.log('Resposta da API:', response); // 🔍 LOG NO CONSOLE

        if (response?.user) {
          this.emailVerified = response.user.emailVerified;
          this.verificationMessage = response.verificationMessage || 'Seu e-mail ainda não foi verificado.';
        }
      },
      error: (err) => {
        console.error('Erro ao buscar status de verificação:', err);
      }
    });
  }

  reenviarEmailVerificacao() {
    this.authService.resendVerificationEmail().subscribe({
      next: () => {
        alert('E-mail de verificação reenviado com sucesso! Verifique sua caixa de entrada.');
      },
      error: (err) => {
        alert('Erro ao reenviar e-mail. Tente novamente mais tarde.');
        console.error(err);
      }
    });
  }

  logout(): void {
    this.authService.logout();
    this.router.navigate(['/login']);
  }
}
